export const SESIONES_MODULO_2 = [
    { orden: 1, semana: 5, dia: "LUNES", titulo: "Â¿QuÃ© problema resuelve React en KaledDental?", descripcion: "De HTML+JS espagueti a componentes reutilizables. JSX, props, primer componente. La tarjeta de cita dental como componente.", duracion: 180, sessionType: "TEORIA", video: { url: "https://www.youtube.com/watch?v=7iobxzd_2wY", title: "React desde cero en espaÃ±ol â€” HolaMundo" }, kaledIntro: "Imagina el dashboard de KaledDental: una lista de 50 citas del dÃ­a, cada una con la foto del paciente, su nombre, la hora, el procedimiento y el estado (pendiente/en curso/completado). Sin React: 50 copias del mismo HTML, 50 lugares donde actualizar cuando cambia el diseÃ±o. Con React: **un componente `<CitaCard>` que se renderiza 50 veces con datos diferentes**. Eso es el poder de los componentes.", analogia: "React es como el catÃ¡logo de productos estÃ¡ndar de KaledWash. En lugar de que cada lavadero diseÃ±e su propia ficha de producto desde cero, KaledSoft crea un componente `<ServicioCard>` que acepta props (nombre, precio, descripciÃ³n, imagen) y lo reutiliza para los 50 lavaderos clientes. Si necesitas cambiar el diseÃ±o de la tarjeta, lo cambias en UN lugar y se actualiza automÃ¡ticamente para todos.", concepts: [{ key: "jsx", title: "JSX â€” HTML inteligente", body: "JSX no es HTML ni JavaScript puro. Es azÃºcar sintÃ¡ctica que Babel compila a `React.createElement()`. Por eso `className` en lugar de `class`, `htmlFor` en lugar de `for`, y las expresiones JavaScript van entre `{}`." }, { key: "props", title: "Props â€” CÃ³mo se parametriza un componente", body: "Las props son como los parÃ¡metros de una funciÃ³n. `<CitaCard paciente='Carlos LÃ³pez' hora='10:30' estado='PENDIENTE' />`. El componente recibe esos datos y los usa para renderizar. Las props son inmutables â€” el componente no puede modificarlas." }], cral: [{ phase: "CONSTRUIR", title: "Componente CitaCard de KaledDental", desc: "Crea el componente `<CitaCard>` de KaledDental con props: paciente (string), hora (string), procedimiento (string), estado ('PENDIENTE'|'EN_CURSO'|'COMPLETADO'). El estado determina el color del badge. Renderiza 5 citas diferentes con el mismo componente." }, { phase: "ROMPER", title: "Props de tipo incorrecto", desc: "Pasa `estado={123}` cuando el componente espera un string. Â¿QuÃ© pasa? Agrega PropTypes o TypeScript para que el error sea detectado en desarrollo, no en producciÃ³n con datos reales de pacientes." }, { phase: "AUDITAR", title: "Â¿El componente de Kaled tiene demasiadas responsabilidades?", desc: "PÃ­dele a Kaled que cree el componente CitaCard. Â¿Hace fetch de datos directamente? Â¿Calcula cosas que deberÃ­an estar en el padre? Un componente bien diseÃ±ado solo se preocupa por mostrar los datos que recibe â€” nada mÃ¡s." }, { phase: "LANZAR", title: "CatÃ¡logo de citas de KaledDental", desc: "App Vite/React con 5+ CitaCards con datos reales de citas dentales ficticias. Cada tarjeta muestra diferente estado con el badge de color correcto. README explica la decisiÃ³n de componentizaciÃ³n." }], quiz: { question: "KaledDental necesita mostrar las citas del dÃ­a. El diseÃ±ador cambiÃ³ el badge de estado de cuadrado a redondo. Â¿CuÃ¡ntos archivos hay que modificar con componentes vs sin componentes?", options: [{ label: "A", text: "50 archivos sin componentes â€” uno por cita renderizada en HTML estÃ¡tico", isCorrect: false, feedback: "Con HTML estÃ¡tico serÃ­an exactamente tantos archivos como citas. Con 100 citas al dÃ­a, serÃ­a 100 cambios manuales." }, { label: "B", text: "1 archivo con componentes â€” el componente CitaCard", isCorrect: true, feedback: "âœ… Â¡Exacto! Ese es el valor fundamental de los componentes. Un cambio en el diseÃ±o se hace en un solo lugar y se propaga a todos los usos. KaledDental tiene este componente usado en el dashboard, en el historial del paciente y en el mÃ³dulo de reportes â€” 3 lugares, 0 cambios extra. ðŸŽ¯" }, { label: "C", text: "3 archivos â€” uno por cada lugar donde se usa CitaCard", isCorrect: false, feedback: "Si el componente estÃ¡ bien diseÃ±ado (toda la lÃ³gica visual encapsulada en CitaCard), cambias solo el componente. Los lugares donde se usa no necesitan cambios â€” solo `<CitaCard {...props} />`." }, { label: "D", text: "Depende del framework CSS que uses", isCorrect: false, feedback: "El framework CSS (Tailwind, Bootstrap, CSS modules) no determina cuÃ¡ntos archivos cambiar. La arquitectura de componentes sÃ­ â€” si estÃ¡ centralizada en CitaCard, es 1 cambio." }] } },
    { orden: 2, semana: 5, dia: "MIERCOLES", titulo: "Estado y efectos: el dashboard de KaledWash en tiempo real", descripcion: "useState para UI interactiva. useEffect para sincronizaciÃ³n. El carrito de servicios del lavadero como ejercicio de estado.", duracion: 180, sessionType: "PRACTICA", video: { url: "https://www.youtube.com/watch?v=O6P86uwfdR0", title: "useState y useEffect â€” Midudev" }, kaledIntro: "El dashboard de KaledWash necesita mostrar en tiempo real cuÃ¡ntos vehÃ­culos estÃ¡n en el lavadero, el estado de cada orden y el total del turno. **Cuando el empleado marca una orden como 'lista', el dashboard debe actualizarse inmediatamente sin recargar la pÃ¡gina**. Eso es estado en React.", analogia: "El estado de un componente es como el pizarrÃ³n de KaledWash donde el supervisor anota el estado de cada vehÃ­culo. Cuando un empleado cambia el estado de 'En lavado' a 'Listo', el supervisor borra lo anterior y escribe el nuevo estado â€” el pizarrÃ³n (la UI) refleja inmediatamente el cambio. `useState` es el pizarrÃ³n. `setState` es la mano que borra y reescribe.", concepts: [{ key: "inmutabilidad", title: "Inmutabilidad â€” Por quÃ© nunca mutas el estado directamente", body: "React compara referencias, no valores profundos. `ordenes.push(nuevaOrden)` modifica el mismo array â€” React ve la misma referencia y no re-renderiza. La forma correcta: `setOrdenes([...ordenes, nuevaOrden])` â€” crea un nuevo array con nueva referencia." }, { key: "useeffect", title: "useEffect â€” SincronizaciÃ³n con el mundo exterior", body: "useEffect con `[]` = se ejecuta una vez al montar el componente (cargar datos iniciales). Con `[id]` = se ejecuta cuando `id` cambia (recargar datos del vehÃ­culo seleccionado). Sin array = se ejecuta en cada render (peligroso â€” puede causar loops infinitos)." }], cral: [{ phase: "CONSTRUIR", title: "Panel de Ã³rdenes de KaledWash con useState", desc: "Construye el panel de Ã³rdenes del lavadero: lista de Ã³rdenes con estado (RECIBIDO/LAVANDO/LISTO/ENTREGADO), botones para cambiar el estado, contador de vehÃ­culos por estado, total del turno. Todo con useState â€” sin backend todavÃ­a." }, { phase: "ROMPER", title: "Muta el estado directamente y observa el bug", desc: "Reemplaza `setOrdenes([...ordenes, nueva])` con `ordenes.push(nueva); setOrdenes(ordenes)`. Â¿La UI actualiza? Â¿Por quÃ© no? Activa las React DevTools y observa quÃ© pasa con el estado. Documenta el bug y la soluciÃ³n." }, { phase: "AUDITAR", title: "Â¿El useEffect tiene dependencias correctas?", desc: "PÃ­dele a Kaled que agregue un useEffect que recargue las Ã³rdenes de KaledWash cuando cambia el estado de una. Verifica: Â¿el array de dependencias estÃ¡ completo? Â¿PodrÃ­a causar un loop infinito? Â¿Hay una funciÃ³n de cleanup para cancelar el fetch si el componente se desmonta?" }, { phase: "LANZAR", title: "Panel de KaledWash en producciÃ³n", desc: "Panel de Ã³rdenes del lavadero con estado gestionado correctamente. Estados visuales claros para cada fase. Contador en tiempo real. GitHub + deploy en Vercel." }], quiz: { question: "En KaledWash, al hacer clic en 'Marcar como Listo', el estado del vehÃ­culo no cambia en la UI aunque el cÃ³digo parece correcto. El developer dice 'cambiÃ© el estado pero React no re-renderiza'. Â¿CuÃ¡l es el bug mÃ¡s probable?", options: [{ label: "A", text: "React tiene un bug â€” a veces no detecta cambios de estado correctamente", isCorrect: false, feedback: "React siempre re-renderiza cuando el estado cambia correctamente. Si no re-renderiza, el problema es en cÃ³mo se estÃ¡ cambiando el estado, no en React." }, { label: "B", text: "El estado se estÃ¡ mutando directamente (ej: `ordenes[0].estado = 'LISTO'` sin crear un nuevo array)", isCorrect: true, feedback: "âœ… Â¡Exacto! Mutar el objeto directamente no crea una nueva referencia â€” React compara referencias y ve la misma referencia, concluye que no cambiÃ³ nada y no re-renderiza. La soluciÃ³n: `setOrdenes(ordenes.map(o => o.id === id ? {...o, estado: 'LISTO'} : o))` â€” crea nuevos objetos y nuevo array. ðŸŽ¯" }, { label: "C", text: "Falta hacer `forceUpdate()` para forzar el re-render", isCorrect: false, feedback: "`forceUpdate()` es un antipatrÃ³n de React que no existe en componentes funcionales. Si necesitas `forceUpdate`, es seÃ±al de que el manejo de estado estÃ¡ incorrecto." }, { label: "D", text: "El componente necesita tener `key` prop para que React lo re-renderice", isCorrect: false, feedback: "`key` es para listas de componentes para que React identifique cuÃ¡les cambiar, no para forzar re-renders de estado. El problema es la mutaciÃ³n directa del estado." }] } },
    { orden: 3, semana: 5, dia: "VIERNES", titulo: "ComponentizaciÃ³n profesional: Atomic Design en KaledSoft", descripcion: "CÃ³mo dividir la UI de KaledSoft en componentes reutilizables. Ãtomos, molÃ©culas, organismos. El design system que comparten todos los productos.", duracion: 180, sessionType: "ENTREGABLE", video: { url: "https://www.youtube.com/watch?v=Yi-HKnZCkA4", title: "Atomic Design para React â€” en espaÃ±ol" }, kaledIntro: "KaledSoft tiene 4 productos: KaledDental, KaledWash, KaledPark y KaledSchool. Todos usan el mismo botÃ³n primario, la misma tarjeta de informaciÃ³n, el mismo sidebar de navegaciÃ³n â€” con diferentes colores y logos. Eso se llama **design system** y es exactamente lo que Atomic Design permite construir.", analogia: "Ãtomos = los ladrillos de LEGO individuales (un botÃ³n, un input, un badge). MolÃ©culas = una combinaciÃ³n pequeÃ±a de ladrillos (un campo de bÃºsqueda = input + botÃ³n + Ã­cono). Organismos = secciones completas (el header de KaledDental = logo + navegaciÃ³n + avatar + notificaciones). Con el mismo set de ladrillos, KaledSoft construye 4 productos diferentes.", concepts: [{ key: "atomicdesign", title: "Atomic Design en la prÃ¡ctica", body: "Ãtomo: `<Button variant='primary' size='md'>`. MolÃ©cula: `<SearchBar placeholder='Buscar paciente' onSearch={fn}>` (Input + Button). Organismo: `<PatientCard patient={data}>` (Avatar + Nombre + Info + Actions)." }], cral: [{ phase: "CONSTRUIR", title: "Design system de KaledSoft en papel", desc: "Dibuja el Ã¡rbol de componentes de KaledWash: Â¿cuÃ¡les son los Ã¡tomos (Button, Badge, Avatar, Input)? Â¿Las molÃ©culas (SearchBar, OrderStatusBadge)? Â¿Los organismos (OrderCard, SummaryPanel)? Hazlo en papel antes de escribir cÃ³digo." }, { phase: "ROMPER", title: "Componente con responsabilidad mÃºltiple", desc: "Crea un componente `<OrderManager>` que hace fetch, procesa datos, valida y renderiza todo en un solo componente de 300 lÃ­neas. Â¿Puedes reutilizarlo? Â¿Puedes testearlo? Ahora divÃ­delo en componentes con responsabilidad Ãºnica y compara." }, { phase: "AUDITAR", title: "EvalÃºa la divisiÃ³n de componentes de Kaled", desc: "PÃ­dele a Kaled que divida la UI de KaledDental (lista de citas + formulario de nueva cita + estadÃ­sticas del dÃ­a) en componentes. Â¿Propone componentes que tienen demasiado o demasiado poco? Â¿Un solo componente hace fetch Y renderiza? Â¿CÃ³mo separarÃ­as data-fetching de presentation?" }, { phase: "LANZAR", title: "CatÃ¡logo React con Atomic Design", desc: "App de catÃ¡logo de servicios de KaledWash con arquitectura Atomic Design documentada. Cada componente en su carpeta correcta (atoms/, molecules/, organisms/). README con el diagrama del Ã¡rbol de componentes." }], quiz: { question: "El componente `<OrderCard>` de KaledWash hace fetch de la API, calcula el total, valida los datos y renderiza la tarjeta. Â¿CuÃ¡ntos problemas de diseÃ±o tiene?", options: [{ label: "A", text: "Ninguno â€” un componente que lo hace todo es mÃ¡s simple de mantener", isCorrect: false, feedback: "Un componente con mÃºltiples responsabilidades es difÃ­cil de testear (Â¿cÃ³mo testeas el renderizado sin hacer una peticiÃ³n HTTP?), difÃ­cil de reutilizar (Â¿quÃ© pasa si quieres mostrar una orden sin fetching?) y difÃ­cil de modificar." }, { label: "B", text: "Viola el Principio de Responsabilidad Ãšnica â€” debe dividirse en: hook para fetch, funciÃ³n para cÃ¡lculo, componente para renderizado", isCorrect: true, feedback: "âœ… Â¡Correcto! `useOrderData(id)` hook para el fetching. `calculateTotal(items)` funciÃ³n pura para el cÃ¡lculo. `<OrderCard order={data}>` componente para el renderizado. Cada parte se puede testear y reutilizar independientemente. ðŸŽ¯" }, { label: "C", text: "Solo tiene un problema: hace fetch â€” deberÃ­a recibirlo por props", isCorrect: false, feedback: "El fetch es un problema, pero el cÃ¡lculo mezclado con el renderizado tambiÃ©n lo es. La soluciÃ³n completa separa las 3 responsabilidades: data, lÃ³gica y presentaciÃ³n." }, { label: "D", text: "El problema es que no usa Redux para el estado global", isCorrect: false, feedback: "Redux (o Zustand) es para estado compartido entre componentes. Este problema es de diseÃ±o de responsabilidades dentro del componente, no de gestiÃ³n de estado global." }], entregable: { title: "CatÃ¡logo de servicios de KaledWash con Atomic Design", desc: "App React con Atomic Design: Ã¡tomos, molÃ©culas y organismos documentados. Lista generada con .map(), filtros con useState. README con Ã¡rbol de componentes.", isFinal: false, items: ["Estructura de carpetas atoms/, molecules/, organisms/", "Al menos 3 Ã¡tomos reutilizables (Button, Badge, Avatar)", "Al menos 2 molÃ©culas (SearchBar, ServiceCard)", "Lista generada con .map() desde datos en JSON", "Filtro por categorÃ­a con useState", "README con diagrama del Ã¡rbol de componentes"] } } },
    { orden: 4, semana: 6, dia: "LUNES", titulo: "Next.js App Router: la arquitectura del SaaS moderno", descripcion: "Por quÃ© Next.js sobre React puro. App Router vs Pages Router. Server Components vs Client Components. El dashboard de KaledSoft como primer proyecto.", duracion: 180, sessionType: "TEORIA", video: { url: "https://www.youtube.com/watch?v=wm5gMKuwSYk", title: "Next.js 14 App Router â€” Midudev" }, kaledIntro: "Next.js es el framework que usa KaledSoft para todos sus productos. La razÃ³n es simple: **un framework que unifica frontend y backend en el mismo repositorio**, con renderizado en servidor para mejorar el SEO de las landing pages y carga de datos segura sin exponer la BD al browser. KaledDental, KaledWash y KaledPark son todos Next.js.", analogia: "React puro es como tener un taller mecÃ¡nico donde cada herramienta estÃ¡ suelta. Next.js es como el taller ya organizado: las herramientas estÃ¡n en su lugar (routing, SSR, optimizaciÃ³n de imÃ¡genes, API routes), el espacio estÃ¡ diseÃ±ado para el trabajo (estructura de carpetas), y hay procedimientos estÃ¡ndar (convenciones sobre configuraciÃ³n). KaledSoft eligiÃ³ Next.js para no reinventar la infraestructura en cada producto.", concepts: [{ key: "server-components", title: "Server Components (SC) â€” El default de App Router", body: "Se renderizan en el servidor. Pueden leer la BD directamente. No envÃ­an JavaScript al browser. Mejoran el Core Web Vitals. El dashboard de KaledDental carga los datos de citas del dÃ­a en el servidor â€” el browser solo recibe HTML." }, { key: "client-components", title: "Client Components ('use client') â€” Para interactividad", body: "Hydratados en el browser. Pueden usar useState, useEffect, event handlers. Declarados con `'use client'` al inicio del archivo. El selector de estado de una orden en KaledWash es Client Component â€” necesita responder a clics del usuario." }, { key: "approuter", title: "Convenciones de App Router", body: "`layout.tsx` = shell que persiste entre navegaciones (sidebar + header de KaledDental). `page.tsx` = contenido de cada ruta. `loading.tsx` = skeleton mientras carga. `error.tsx` = error boundary. `not-found.tsx` = 404 customizado." }], cral: [{ phase: "CONSTRUIR", title: "Dashboard de KaledPark en Next.js", desc: "npx create-next-app@latest kaledpark-demo. Crea rutas: `/dashboard` (resumen del dÃ­a), `/vehiculos` (lista), `/vehiculos/[placa]` (detalle). El layout incluye sidebar con navegaciÃ³n. El dashboard muestra datos hardcodeados inicialmente." }, { phase: "ROMPER", title: "Usa useState en un Server Component", desc: "Agrega `useState` a un Server Component sin `'use client'`. Â¿QuÃ© error obtienes? Â¿El mensaje de error es claro? Â¿CÃ³mo decidirÃ­as si un componente debe ser Server o Client Component?" }, { phase: "AUDITAR", title: "Â¿CuÃ¡ntos Client Components necesita realmente KaledPark?", desc: "Analiza el dashboard de KaledPark que construiste: Â¿cuÃ¡les componentes REALMENTE necesitan interactividad (estado, eventos)? Â¿CuÃ¡les podrÃ­an ser Server Components? Menos Client Components = menos JavaScript al browser = app mÃ¡s rÃ¡pida." }, { phase: "LANZAR", title: "Dashboard de KaledPark en Vercel", desc: "App Next.js con App Router conectada a Vercel. URL pÃºblica. Al menos 3 rutas funcionando. README documenta cuÃ¡les componentes son Server y cuÃ¡les Client, y por quÃ©." }], quiz: { question: "En el dashboard de KaledWash, el componente que muestra el total del turno actualizado en tiempo real, Â¿debe ser Server Component o Client Component?", options: [{ label: "A", text: "Server Component â€” los datos vienen del servidor", isCorrect: false, feedback: "El problema es 'tiempo real' â€” si necesita actualizarse sin recargar la pÃ¡gina (cada vez que se complete una orden), necesita estado del cliente y posiblemente polling o websockets. Los Server Components se renderizan una vez en el servidor." }, { label: "B", text: "Client Component â€” necesita actualizar la UI sin recargar la pÃ¡gina (useState + polling o websockets)", isCorrect: true, feedback: "âœ… Â¡Correcto! Cualquier componente que necesita reaccionar a eventos del usuario o actualizarse dinÃ¡micamente sin navegaciÃ³n completa es Client Component. El 'tiempo real' es la clave: estado cambiante = Client Component. ðŸŽ¯" }, { label: "C", text: "Server Component con `revalidate: 30` para que Next.js lo regenere cada 30 segundos", isCorrect: false, feedback: "ISR con `revalidate` es para contenido que no cambia muy frecuentemente (ej: catÃ¡logo de precios). Para tiempo real con segundos de granularidad, necesitas Client Component con estado local." }, { label: "D", text: "Depende de Vercel â€” si estÃ¡ en el plan Pro puede ser Server Component en tiempo real", isCorrect: false, feedback: "El plan de Vercel no determina si un componente es Server o Client. Esa es una decisiÃ³n de arquitectura basada en los requisitos de interactividad." }] } },
    { orden: 5, semana: 6, dia: "MIERCOLES", titulo: "Tailwind CSS + shadcn/ui: el design system de KaledSoft", descripcion: "Utility-first CSS en producciÃ³n. shadcn/ui: componentes que instalas y posees. El dashboard de KaledDental rediseÃ±ado con Tailwind.", duracion: 180, sessionType: "PRACTICA", video: { url: "https://www.youtube.com/watch?v=lCxcTsOHrjo", title: "Tailwind CSS desde cero â€” Midudev" }, kaledIntro: "KaledSoft usa Tailwind CSS + shadcn/ui en todos sus productos. La razÃ³n: **Tailwind elimina la fricciÃ³n de nombrar clases CSS** (Â¿cuÃ¡l era el nombre correcto? `.card-container` o `.contenedor-tarjeta`?) y shadcn/ui provee componentes profesionales cuyo cÃ³digo fuente posees y puedes modificar â€” no una librerÃ­a negra.", analogia: "CSS tradicional es como mandarle a un carpintero las especificaciones tÃ©cnicas ('quiero una mesa de 1.2m x 0.8m, roble, 4 patas torneadas, lacada en blanco mate'). Tailwind es como comprar en IKEA: piezas estandarizadas que ensamblas rÃ¡pido. shadcn/ui es como IKEA con el plano de ensamblado incluido: puedes modificar la mesa si necesitas algo diferente. KaledSoft no reinventa el Button component â€” usa el de shadcn y lo ajusta a su brand.", concepts: [{ key: "tailwind-responsive", title: "Prefijos responsivos en Tailwind", body: "`sm:hidden md:flex lg:w-64` â€” oculto en mÃ³vil, flex en tablet, 256px en desktop. Mobile-first: sin prefijo = todos los tamaÃ±os. El sidebar de KaledWash es `hidden md:flex flex-col w-64`." }, { key: "shadcn", title: "shadcn/ui â€” Componentes que posees", body: "`npx shadcn@latest add button card dialog table`. Los archivos se copian a `src/components/ui/`. Puedes modificarlos. No son una dependencia opaca â€” son tu cÃ³digo. Si KaledDental necesita un Badge con colores especÃ­ficos para estados dentales, modificas directamente el archivo." }], cral: [{ phase: "CONSTRUIR", title: "Dashboard de KaledDental con Tailwind + shadcn/ui", desc: "RediseÃ±a el dashboard de KaledPark con Tailwind CSS. Instala shadcn/ui y usa: Card para estadÃ­sticas, Table para lista de vehÃ­culos, Badge para estados, Button para acciones. El resultado debe verse profesional en mÃ³vil y desktop." }, { phase: "ROMPER", title: "Usa una clase de Tailwind que no existe", desc: "Escribe `bg-kaledsoft-blue` o `w-[347.5px]` en un componente. Â¿QuÃ© pasa? Â¿Tailwind muestra un error o simplemente ignora la clase? Â¿CÃ³mo detectarÃ­as este bug en producciÃ³n? (Respuesta: la clase simplemente no aplica â€” sin error en consola)." }, { phase: "AUDITAR", title: "Lee el cÃ³digo de Button de shadcn/ui", desc: "Abre `src/components/ui/button.tsx`. Â¿Entiendes cÃ³mo funciona `cva` (class-variance-authority) para las variantes? Â¿CÃ³mo agregarÃ­as una variante `variant='kaledsoft'` con los colores del brand? Â¿Kaled te puede explicar cva paso a paso?" }, { phase: "LANZAR", title: "App Next.js rediseÃ±ada con Tailwind + shadcn/ui en Vercel", desc: "Dashboard rediseÃ±ado en Vercel. Responsive en mÃ³vil verificado con DevTools. Al menos 3 componentes de shadcn/ui usados y personalizados." }], quiz: { question: "En el dashboard de KaledPark, el Badge de estado 'OCUPADO' debe ser rojo en mobile y azul en desktop (por requerimiento extraÃ±o del cliente). Con Tailwind, Â¿cÃ³mo lo implementarÃ­as?", options: [{ label: "A", text: "`className='bg-red-500 desktop:bg-blue-500'` â€” Tailwind tiene prefijos para desktop", isCorrect: false, feedback: "Tailwind no tiene prefijo `desktop`. Los prefijos son `sm:`, `md:`, `lg:`, `xl:`, `2xl:`. No existe `desktop:`." }, { label: "B", text: "`className='bg-red-500 md:bg-blue-500'` â€” rojo por defecto (mÃ³vil), azul desde 768px", isCorrect: true, feedback: "âœ… Â¡Correcto! Mobile-first: sin prefijo = todos los tamaÃ±os (incluido mÃ³vil). `md:` = aplica desde 768px (tablet/desktop). El Badge serÃ­a rojo en mÃ³vil y azul en tablet y desktop. Aunque este requerimiento sea extraÃ±o, Tailwind lo maneja limpiamente. ðŸŽ¯" }, { label: "C", text: "No es posible con Tailwind â€” necesitas JavaScript para detectar el tamaÃ±o de pantalla", isCorrect: false, feedback: "Las media queries responsivas son una caracterÃ­stica core de Tailwind. No necesitas JavaScript para esto â€” el CSS de Tailwind maneja los breakpoints automÃ¡ticamente." }, { label: "D", text: "`className={isMobile ? 'bg-red-500' : 'bg-blue-500'}` con useState y window.innerWidth", isCorrect: false, feedback: "Funciona pero es innecesariamente complejo, causa problemas de hidrataciÃ³n en Next.js SSR, y es mÃ¡s lento que CSS puro. Los prefijos responsivos de Tailwind son la soluciÃ³n correcta y eficiente." }] } },
    { orden: 6, semana: 6, dia: "VIERNES", titulo: "Routing avanzado: la navegaciÃ³n profesional de KaledSoft", descripcion: "Rutas dinÃ¡micas [id], grupos de rutas, layouts anidados. Loading UI, Error Boundaries. Metadata para SEO. Estructura de navegaciÃ³n completa del SaaS.", duracion: 180, sessionType: "ENTREGABLE", video: { url: "https://www.youtube.com/watch?v=ZjAqacIC_3c", title: "Next.js App Router routing completo" }, kaledIntro: "KaledDental tiene rutas para cada paciente (`/pacientes/[pacienteId]`), para cada cita (`/citas/[citaId]`), para el perfil del odontÃ³logo (`/perfil`), para el admin del consultorio (`/admin/usuarios`). **Todas estas rutas comparten el mismo sidebar y header** â€” gracias a los layouts anidados de Next.js. Hoy construyes esa arquitectura de navegaciÃ³n.", analogia: "El routing de Next.js es como la estructura de pisos de un hospital. El layout raÃ­z (recepciÃ³n y pasillos) estÃ¡ presente en todos los pisos. El layout de 'OdontologÃ­a' estÃ¡ presente en todas las consultas del piso 3. Cada consultorio especÃ­fico es una `page.tsx`. Cambiar la recepciÃ³n (layout raÃ­z) afecta a todo el hospital â€” cambiar un consultorio solo afecta esa habitaciÃ³n.", concepts: [{ key: "dynamic-routes", title: "Rutas dinÃ¡micas â€” Parametrizar URLs", body: "`app/vehiculos/[placa]/page.tsx` â†’ `/vehiculos/ABC123`. En el componente: `const { placa } = params`. `app/vehiculos/[placa]/servicios/[servicioId]/page.tsx` â†’ rutas anidadas dinÃ¡micas para KaledWash." }, { key: "not-found", title: "not-found.tsx â€” La pÃ¡gina 404 de tu SaaS", body: "Cuando un odontÃ³logo busca un paciente que no existe en KaledDental, debe ver: '404 â€” Paciente no encontrado' con un botÃ³n para volver al listado. Sin un `not-found.tsx` customizado, Next.js muestra su 404 genÃ©rico." }], cral: [{ phase: "CONSTRUIR", title: "Estructura de rutas completa de KaledWash", desc: "Implementa las rutas de KaledWash: `/dashboard` (resumen), `/ordenes` (lista), `/ordenes/[id]` (detalle + cambio de estado), `/clientes` (lista), `/clientes/[id]` (historial de visitas), `/configuracion` (admin). Con loading.tsx y error.tsx en cada ruta." }, { phase: "ROMPER", title: "Accede a una ruta que no existe", desc: "Navega a `/ordenes/id-que-no-existe` en tu app. Â¿QuÃ© muestra Next.js? Implementa el flujo correcto: en el Server Component, si `orden === null`, llama a `notFound()` de Next.js â€” esto renderiza el `not-found.tsx`." }, { phase: "AUDITAR", title: "Metadata dinÃ¡mica para SEO", desc: "La ruta `/vehiculos/ABC123` de KaledPark debe tener `<title>VehÃ­culo ABC123 | KaledPark</title>`. Implementa `generateMetadata()` en el Server Component. PÃ­dele a Kaled cÃ³mo hacerlo y verifica en las DevTools que el title cambia segÃºn la placa." }, { phase: "LANZAR", title: "App Next.js en Vercel con navegaciÃ³n completa", desc: "Dashboard de KaledWash en Vercel con todas las rutas funcionando, loading states visibles, error boundaries activos y metadata SEO en cada ruta. URL pÃºblica." }], quiz: { question: "En KaledDental, el link `/pacientes/123` tarda 3 segundos en cargar porque hace un fetch pesado. Â¿CÃ³mo mejorarÃ­as la experiencia del odontÃ³logo mientras espera?", options: [{ label: "A", text: "Poner un alert() de JavaScript que diga 'Cargando...' mientras espera", isCorrect: false, feedback: "`alert()` es sincrÃ³nico â€” bloquea el browser hasta que el usuario lo cierra. Es la peor UX posible. Nunca uses `alert()` en cÃ³digo de producciÃ³n." }, { label: "B", text: "Crear `app/pacientes/[id]/loading.tsx` con un skeleton que se muestra automÃ¡ticamente mientras hace el fetch", isCorrect: true, feedback: "âœ… Â¡Correcto! Next.js usa Suspense internamente: mientras el Server Component hace el fetch, renderiza el `loading.tsx` del mismo directorio. El skeleton mantiene al usuario informado y la percepciÃ³n de velocidad mejora aunque el tiempo real sea el mismo. ðŸŽ¯" }, { label: "C", text: "Reducir el tamaÃ±o de la imagen del paciente para que cargue mÃ¡s rÃ¡pido", isCorrect: false, feedback: "Las imÃ¡genes son parte del problema pero 'fetch pesado' sugiere que los datos toman tiempo, no las imÃ¡genes. El `loading.tsx` mejora la percepciÃ³n mientras el fetch completa, independientemente de la causa." }, { label: "D", text: "Hacer el fetch en el cliente con useEffect para no bloquear la renderizaciÃ³n inicial", isCorrect: false, feedback: "Mover el fetch al cliente con useEffect mostrarÃ­a la pÃ¡gina vacÃ­a y luego cargarÃ­a los datos â€” el efecto visual es el mismo o peor. El `loading.tsx` con Server Components es la soluciÃ³n correcta en Next.js." }], entregable: { title: "App Next.js con navegaciÃ³n completa en Vercel", desc: "Dashboard de KaledWash en Vercel con rutas dinÃ¡micas, layouts anidados, loading.tsx, error.tsx, y metadata SEO en cada ruta.", isFinal: false, items: ["Al menos 5 rutas funcionando incluyendo una dinÃ¡mica [id]", "layout.tsx con sidebar que persiste entre navegaciones", "loading.tsx visible mientras cargan los datos", "error.tsx que maneja errores gracefully", "not-found.tsx para recursos inexistentes", "Metadata (title, description) diferente en cada ruta", "Deploy en Vercel con URL pÃºblica"] } } },
    { orden: 7, semana: 7, dia: "LUNES", titulo: "Estado global con Zustand: el carrito de KaledWash", descripcion: "Prop drilling como problema. Context API vs Zustand. CuÃ¡ndo escalar el estado. El carrito de servicios del lavadero como ejercicio real.", duracion: 180, sessionType: "PRACTICA", video: { url: "https://www.youtube.com/watch?v=fZPgBnL2x-Q", title: "Zustand en 15 minutos â€” Midudev" }, kaledIntro: "En KaledWash, cuando el empleado selecciona servicios para un vehÃ­culo, el carrito de servicios debe ser visible en 3 lugares: el panel de selecciÃ³n, el resumen del sidebar y el total en el header. **Pasar ese estado por props entre 5 componentes es el infierno del prop drilling**. Zustand resuelve esto con elegancia brutal.", analogia: "El estado local (useState) es el cuaderno del empleado individual â€” solo Ã©l lo ve. El estado global (Zustand) es la pantalla central del lavadero que todos pueden ver y actualizar. Cuando el empleado 1 agrega el servicio de aspirado, el empleado 2 en la caja ya ve el nuevo total sin que nadie le avise manualmente. Eso es el store de Zustand.", concepts: [{ key: "zustand-patron", title: "PatrÃ³n de store en Zustand", body: "`create((set) => ({ carrito: [], agregar: (s) => set(p => ({carrito: [...p.carrito, s]})), quitar: (id) => set(p => ({carrito: p.carrito.filter(s => s.id !== id)})), total: () => get().carrito.reduce((a, s) => a + s.precio, 0) }))`. Un store por dominio: carritoStore, usuarioStore, uiStore." }], cral: [{ phase: "CONSTRUIR", title: "Store de carrito de KaledWash con Zustand", desc: "Crea el store de Zustand para el carrito de servicios de KaledWash: servicios disponibles, servicios seleccionados, agregar/quitar servicio, calcular total. Ãšsalo en 3 componentes diferentes sin pasar props." }, { phase: "ROMPER", title: "Re-renders innecesarios con Zustand", desc: "Suscribe un componente al store completo (`useStore()`) y otro solo a `carrito` (`useStore(s => s.carrito)`). Agrega un servicio al carrito. Â¿CuÃ¡l componente re-renderiza? Usa React DevTools Profiler para verificar." }, { phase: "AUDITAR", title: "Â¿CuÃ¡nto estado global es demasiado?", desc: "PÃ­dele a Kaled que diseÃ±e el estado global de KaledDental (citas, pacientes, odontÃ³logo actual, ui, configuraciÃ³n). Â¿Pone todo en un solo store? Â¿CÃ³mo separarÃ­as por dominio? Â¿QuÃ© deberÃ­a estar en estado local (useState) y quÃ© en global?" }, { phase: "LANZAR", title: "Carrito de KaledWash con persistencia", desc: "Store de Zustand con middleware `persist` para que el carrito sobreviva al refresh. El carrito visible en mÃºltiples componentes sin prop drilling. Deploy en Vercel." }], quiz: { question: "Un developer de KaledSoft pone TODO el estado de la app en un store global de Zustand: el carrito, el usuario logueado, los temas de UI, la configuraciÃ³n del lavadero, los filtros de bÃºsqueda. Â¿QuÃ© problema tiene este enfoque?", options: [{ label: "A", text: "No hay problema â€” centralizar el estado es buena prÃ¡ctica", isCorrect: false, feedback: "Centralizar TODO el estado en un solo store causa: cambios en cualquier parte del store re-renderizan todos los consumidores, el store se vuelve difÃ­cil de mantener y testear, y el estado de UI efÃ­mero (si el modal estÃ¡ abierto) no necesita persistir globalmente." }, { label: "B", text: "Todo estado en global causa re-renders innecesarios y hace el cÃ³digo difÃ­cil de mantener", isCorrect: true, feedback: "âœ… Â¡Correcto! El estado que usa solo un componente debe ser local (useState). El estado que comparten mÃºltiples componentes distantes va a Zustand. Regla de KaledSoft: si el estado no necesita estar en mÃ¡s de 2 componentes directamente relacionados, es local. ðŸŽ¯" }, { label: "C", text: "El problema es usar Zustand â€” deberÃ­a usar Redux que escala mejor", isCorrect: false, feedback: "Zustand escala perfectamente para KaledSoft. Redux es mÃ¡s complejo sin aÃ±adir beneficios para este caso. El problema es el diseÃ±o del estado, no la librerÃ­a." }, { label: "D", text: "No hay problema si se usa el middleware `devtools` de Zustand para debugging", isCorrect: false, feedback: "El middleware devtools ayuda a debuggear pero no resuelve los re-renders innecesarios ni la complejidad de mantener un store monolÃ­tico." }] } },
    { orden: 8, semana: 7, dia: "MIERCOLES", titulo: "Formularios con React Hook Form + Zod: validaciÃ³n real", descripcion: "ValidaciÃ³n del lado del cliente con lÃ³gica real. Por quÃ© el frontend no reemplaza el backend. Formulario de registro de paciente para KaledDental.", duracion: 180, sessionType: "PRACTICA", video: { url: "https://www.youtube.com/watch?v=KejZXxFCe2k", title: "React Hook Form + Zod â€” Midudev" }, kaledIntro: "El formulario de registro de un paciente en KaledDental captura datos crÃ­ticos: nombre completo, cÃ©dula, fecha de nacimiento, alergias a medicamentos, contacto de emergencia. **Un formulario con validaciÃ³n incorrecta puede guardar datos errÃ³neos en la historia clÃ­nica**. React Hook Form + Zod garantizan que los datos son correctos antes de llegar a la base de datos.", analogia: "El formulario de KaledDental es la recepcionista del consultorio. React Hook Form es quien organiza el flujo (quÃ© campo va primero, cuÃ¡ndo mostrar errores, cuÃ¡ndo habilitar el botÃ³n de guardar). Zod es el sistema de verificaciÃ³n de documentos (la cÃ©dula debe ser nÃºmero de 10 dÃ­gitos, el email debe tener @, la fecha de nacimiento no puede ser en el futuro). Pero incluso con la mejor recepcionista, **el mÃ©dico (el backend) verifica de nuevo antes de registrar al paciente** â€” nunca confÃ­as solo en la recepcionista.", concepts: [{ key: "zod-schema", title: "Zod â€” ValidaciÃ³n con TypeScript", body: "`z.object({ cedula: z.string().length(10, 'CÃ©dula debe ser 10 dÃ­gitos'), email: z.string().email('Email invÃ¡lido'), fechaNacimiento: z.date().max(new Date(), 'No puede ser en el futuro'), alergias: z.array(z.string()).optional() })`. El schema genera tipos TypeScript automÃ¡ticamente." }], cral: [{ phase: "CONSTRUIR", title: "Formulario de registro de paciente KaledDental", desc: "Formulario completo con RHF + Zod: nombre (mÃ­nimo 3 letras), cÃ©dula (10 dÃ­gitos, solo nÃºmeros), email, telÃ©fono (10 dÃ­gitos), fecha nacimiento (no en el futuro), alergias (campo mÃºltiple opcional). Errores en tiempo real. BotÃ³n deshabilitado hasta que todo es vÃ¡lido." }, { phase: "ROMPER", title: "Bypasea la validaciÃ³n desde DevTools", desc: "Con el formulario abierto en el navegador, abre la consola y ejecuta: `fetch('/api/pacientes', {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({cedula: 'abc', email: 'no-es-email'})})`. Â¿El backend acepta datos invÃ¡lidos? Â¿QuÃ© aprendes sobre dÃ³nde REALMENTE debe estar la validaciÃ³n?" }, { phase: "AUDITAR", title: "El schema Zod de Kaled no valida casos colombianos", desc: "PÃ­dele a Kaled que genere el schema Zod para el formulario de KaledDental. Verifica: Â¿valida cÃ©dulas colombianas (7-10 dÃ­gitos)? Â¿acepta NIT (para personas jurÃ­dicas, 9-10 dÃ­gitos + dÃ­gito verificador)? Â¿el telÃ©fono acepta celulares colombianos (3XX-XXX-XXXX)?" }, { phase: "LANZAR", title: "Formulario de registro en producciÃ³n de KaledDental", desc: "Formulario con RHF + Zod desplegado en Vercel. Maneja: loading (spinner en el botÃ³n), error del servidor (mensaje de error), Ã©xito (redirecciÃ³n o toast). ValidaciÃ³n en espaÃ±ol colombiano." }], quiz: { question: "El formulario de KaledDental valida que la cÃ©dula sea de 10 dÃ­gitos con Zod. La validaciÃ³n pasa. El backend de KaledSoft, Â¿debe validar tambiÃ©n o puede confiar en el frontend?", options: [{ label: "A", text: "Puede confiar â€” si Zod lo validÃ³ en el frontend, el dato es correcto", isCorrect: false, feedback: "Cualquier persona puede hacer `fetch('/api/pacientes', {method:'POST', body: JSON.stringify({cedula: '123'})})` directamente a la API, saltando completamente el frontend y su validaciÃ³n Zod." }, { label: "B", text: "Siempre debe validar â€” el frontend es completamente ignorable por cualquier usuario con conocimientos tÃ©cnicos", isCorrect: true, feedback: "âœ… Â¡CrÃ­tico! En KaledDental, un atacante podrÃ­a registrar pacientes con datos falsos si el backend no valida. La validaciÃ³n frontend es UX (feedback inmediato al usuario). La validaciÃ³n backend es seguridad (Ãºnica fuente de verdad). Siempre ambas. ðŸŽ¯" }, { label: "C", text: "Depende â€” si el formulario usa HTTPS, la validaciÃ³n estÃ¡ segura", isCorrect: false, feedback: "HTTPS cifra la comunicaciÃ³n en trÃ¡nsito pero no previene que el usuario mismo envÃ­e datos invÃ¡lidos directamente a la API. Son dos conceptos completamente distintos." }, { label: "D", text: "Solo si la API es pÃºblica â€” si requiere autenticaciÃ³n, puede confiar en el frontend", isCorrect: false, feedback: "La autenticaciÃ³n verifica QUIÃ‰N eres. La validaciÃ³n verifica que LOS DATOS sean correctos. Un odontÃ³logo autenticado podrÃ­a igualmente enviar una cÃ©dula invÃ¡lida directamente a la API." }] } },
    { orden: 9, semana: 7, dia: "VIERNES", titulo: "Consumo de APIs: los 4 estados de UI que todo SaaS necesita", descripcion: "fetch en Server Components, Route Handlers, SWR para cliente. Loading, error, empty, success â€” los 4 estados que siempre debes implementar.", duracion: 180, sessionType: "ENTREGABLE", video: { url: "https://www.youtube.com/watch?v=9EmUm7RlRuI", title: "Data Fetching en Next.js 14" }, kaledIntro: "Cuando el odontÃ³logo de KaledDental abre el dashboard por la maÃ±ana, la pantalla no puede quedarse en blanco mientras carga. Cuando la conexiÃ³n falla, no puede mostrar una pantalla rota. Cuando no hay citas del dÃ­a, debe decir claramente que no hay citas. **Los 4 estados â€” loading, error, empty, success â€” son obligatorios en cualquier SaaS profesional**. Si uno falta, el sistema estÃ¡ incompleto.", analogia: "Los 4 estados son como el estado de una orden de domicilio: ðŸ• **Loading** = 'Tu pedido estÃ¡ siendo preparado'. âŒ **Error** = 'No pudimos procesar tu pedido, llama al restaurante'. ðŸ“­ **Empty** = 'No tienes pedidos activos'. âœ… **Success** = 'Tu pedido estÃ¡ listo, aquÃ­ estÃ¡n los detalles'. Cualquier app que solo muestra Success estÃ¡ incompleta.", concepts: [{ key: "4-estados", title: "Los 4 estados de UI â€” Obligatorios en KaledSoft", body: "Loading: skeleton o spinner mientras los datos cargan. Error: mensaje claro + acciÃ³n posible (reintentar). Empty: explicaciÃ³n + llamada a la acciÃ³n (Â¿cÃ³mo crear el primer elemento?). Success: los datos bien presentados. KaledSoft code review automÃ¡ticamente rechaza PRs que no implementen los 4 estados." }], cral: [{ phase: "CONSTRUIR", title: "Dashboard de KaledWash con los 4 estados", desc: "Construye el listado de Ã³rdenes del dÃ­a en KaledWash con SWR: loading (skeleton de 5 filas), error (mensaje + botÃ³n 'Reintentar'), empty (ilustraciÃ³n + 'No hay Ã³rdenes hoy. Registra la primera orden â†’'), success (tabla de Ã³rdenes). Usa la API de JSONPlaceholder como mock." }, { phase: "ROMPER", title: "Simula todos los estados", desc: "Fuerza cada estado: (1) agrega `await new Promise(r => setTimeout(r, 5000))` para simular loading lento, (2) retorna status 500 desde un endpoint para forzar error, (3) retorna `[]` para el estado empty. Â¿Se ven correctamente todos los estados? Â¿El UX es apropiado?" }, { phase: "AUDITAR", title: "El cÃ³digo de Kaled solo implementa success y error", desc: "PÃ­dele a Kaled que implemente el listado de citas de KaledDental. Â¿Implementa los 4 estados? Â¿El estado empty tiene una llamada a la acciÃ³n ('Agendar primera cita')? Â¿El error tiene botÃ³n de reintento? Â¿El loading es un skeleton o solo un spinner genÃ©rico?" }, { phase: "LANZAR", title: "Dashboard de KaledWash con los 4 estados en Vercel", desc: "Dashboard completo con Zustand, RHF+Zod y los 4 estados de UI en todas las vistas. Deploy en Vercel con URL pÃºblica. README documenta las decisiones de estado." }], quiz: { question: "El primer dÃ­a de KaledDental en producciÃ³n, un odontÃ³logo nuevo abre el dashboard. No tiene ningÃºn paciente registrado todavÃ­a. Â¿QuÃ© debe mostrar el sistema?", options: [{ label: "A", text: "Una tabla vacÃ­a â€” el sistema funciona correctamente, simplemente no hay datos", isCorrect: false, feedback: "Una tabla vacÃ­a sin contexto frustrÃ³ al nuevo usuario: 'Â¿El sistema estÃ¡ cargando? Â¿Hubo un error? Â¿No tengo pacientes?'. El usuario no sabe quÃ© hacer a continuaciÃ³n." }, { label: "B", text: "El estado Empty: 'Â¡Bienvenido a KaledDental! AÃºn no tienes pacientes registrados. [Registrar primer paciente â†’]'", isCorrect: true, feedback: "âœ… Â¡Exacto! El estado Empty tiene dos funciones: (1) confirma que el sistema funciona correctamente (no es un error), (2) guÃ­a al usuario hacia la primera acciÃ³n valiosa. Un buen empty state es parte del onboarding. AsÃ­ funciona en KaledSoft. ðŸŽ¯" }, { label: "C", text: "Un spinner de carga â€” quizÃ¡s los pacientes aÃºn estÃ¡n cargando", isCorrect: false, feedback: "Si la API ya respondiÃ³ con un array vacÃ­o, el loading debe terminar. Mostrar un spinner infinito cuando ya se recibiÃ³ respuesta es peor UX que la tabla vacÃ­a." }, { label: "D", text: "Un mensaje de error â€” algo saliÃ³ mal si no hay datos", isCorrect: false, feedback: "Un array vacÃ­o `[]` es una respuesta vÃ¡lida y exitosa de la API, no un error. El error state es para cuando la peticiÃ³n fallÃ³ (timeout, 500, sin conexiÃ³n). El empty state es para cuando la peticiÃ³n exitosa retorna datos vacÃ­os." }], entregable: { title: "Dashboard SaaS con estado global y las 4 UIs de datos", desc: "Dashboard de KaledWash con Zustand, RHF+Zod y los 4 estados (loading, error, empty, success) en todas las vistas. Deploy en Vercel.", isFinal: false, items: ["Zustand store del carrito/estado de Ã³rdenes", "Formulario de registro de orden con RHF + Zod", "4 estados de UI en todas las vistas con datos", "Skeleton de loading (no solo spinner genÃ©rico)", "Empty state con llamada a la acciÃ³n", "Error state con botÃ³n de reintento", "Deploy actualizado en Vercel con URL pÃºblica"] } } },
    { orden: 10, semana: 8, dia: "LUNES", titulo: "Animaciones con Framer Motion: UI que comunica", descripcion: "Animaciones de entrada, transiciones, micro-interacciones. La animaciÃ³n debe comunicar, no decorar. KaledPark con feedback visual en tiempo real.", duracion: 180, sessionType: "PRACTICA", video: { url: "https://www.youtube.com/watch?v=FZuHbFAb7Lk", title: "Framer Motion en espaÃ±ol" }, kaledIntro: "Cuando el empleado de KaledPark marca un vehÃ­culo como 'SaliÃ³', el registro debe desaparecer suavemente de la lista â€” no cortar abruptamente. Cuando llega un nuevo vehÃ­culo, su tarjeta debe aparecer deslizÃ¡ndose desde arriba. **Estas animaciones no son decoraciÃ³n â€” comunican que el sistema respondiÃ³** a la acciÃ³n del usuario.", analogia: "Una interfaz sin animaciones es como una caja registradora que no emite sonido ni luz al procesar un pago â€” funciona, pero el cajero no sabe si funcionÃ³. Las animaciones en KaledPark son el feedback visual que le dice al empleado: 'SÃ­, tu acciÃ³n fue registrada'. La ausencia de animaciones no es minimalismo â€” es falta de comunicaciÃ³n.", concepts: [{ key: "motion", title: "Framer Motion â€” Animaciones declarativas en React", body: "`<motion.div initial={{opacity:0, y:20}} animate={{opacity:1, y:0}} exit={{opacity:0, y:-20}} transition={{duration:0.3}}>`. Con `AnimatePresence` para animar elementos que salen del DOM (vehÃ­culos que salen del parqueadero)." }], cral: [{ phase: "CONSTRUIR", title: "Animaciones en el panel de KaledPark", desc: "Agrega animaciones a la lista de vehÃ­culos de KaledPark: entrada suave cuando llega un nuevo vehÃ­culo (slide desde arriba), salida cuando se va (fade + slide hacia arriba). El cambio de estado (LIBRE â†’ OCUPADO) tiene transiciÃ³n de color animada." }, { phase: "ROMPER", title: "AnimaciÃ³n que destruye la UX", desc: "Configura `transition={{duration: 3}}` en el botÃ³n de 'Registrar salida' de KaledPark. Â¿CuÃ¡ntas veces hace clic el empleado creyendo que no respondiÃ³? Â¿CuÃ¡ntos vehÃ­culos 'salen' dos veces? Aprende cuÃ¡ndo las animaciones daÃ±an la UX operacional." }, { phase: "AUDITAR", title: "Â¿Las animaciones de Kaled comunican o solo decoran?", desc: "PÃ­dele a Kaled que agregue animaciones al dashboard de KaledWash. Para cada animaciÃ³n que proponga, pregunta: 'Â¿QuÃ© le comunica esta animaciÃ³n al usuario? Â¿QuÃ© estado o acciÃ³n indica?' Si no hay una respuesta clara, la animaciÃ³n es decorativa y puede eliminarse." }, { phase: "LANZAR", title: "Panel de KaledPark con animaciones funcionales", desc: "Panel de KaledPark con al menos 3 animaciones que comunican estado (entrada de vehÃ­culo, salida, cambio de estado). Ninguna animaciÃ³n supera 400ms de duraciÃ³n. Deploy en Vercel." }], quiz: { question: "En KaledWash, cuando el empleado marca una orden como 'Lista', la tarjeta de la orden desaparece de la vista 'En Proceso' y aparece en 'Listas'. Â¿QuÃ© tipo de animaciÃ³n es apropiada aquÃ­?", options: [{ label: "A", text: "Una animaciÃ³n de 2 segundos con efecto de fuego y confetti para celebrar la orden lista", isCorrect: false, feedback: "Un efecto visual de 2 segundos repetido docenas de veces al dÃ­a interrumpe el flujo de trabajo del empleado. En interfaces operacionales (usadas continuamente), menos es mÃ¡s." }, { label: "B", text: "Fade out rÃ¡pido (200ms) de la lista actual y fade in (200ms) en la nueva lista â€” comunicando la transiciÃ³n de estado", isCorrect: true, feedback: "âœ… Â¡Correcto! Una transiciÃ³n rÃ¡pida y sutil comunica que el elemento cambiÃ³ de estado sin interrumpir el flujo de trabajo. 200ms es el rango donde el usuario percibe movimiento pero no espera. En contextos operacionales, las animaciones deben ser cortas y funcionales. ðŸŽ¯" }, { label: "C", text: "Sin animaciÃ³n â€” la desapariciÃ³n abrupta es mÃ¡s clara", isCorrect: false, feedback: "Una desapariciÃ³n abrupta puede confundir al empleado: 'Â¿La orden se fue? Â¿La borrÃ© accidentalmente? Â¿El sistema tuvo un error?'. Una transiciÃ³n breve confirma que el sistema procesÃ³ la acciÃ³n intencionalmente." }, { label: "D", text: "Una animaciÃ³n lenta de 1 segundo para que el empleado vea claramente quÃ© pasÃ³", isCorrect: false, feedback: "1 segundo es demasiado lento para una acciÃ³n que el empleado hace 50 veces al dÃ­a. DespuÃ©s de la dÃ©cima vez, el empleado estÃ¡ mirando la pantalla esperando que la animaciÃ³n termine." }] } },
    { orden: 11, semana: 8, dia: "MIERCOLES", titulo: "Performance: el SaaS que cargan rÃ¡pido gana clientes", descripcion: "Core Web Vitals, lazy loading con dynamic(), code splitting. Los 3 problemas de performance mÃ¡s comunes que genera la IA en Next.js.", duracion: 180, sessionType: "PRACTICA", video: { url: "https://www.youtube.com/watch?v=utxD9B6LLCA", title: "Next.js Performance â€” Core Web Vitals" }, kaledIntro: "**Un SaaS que carga lento pierde clientes.** El odontÃ³logo que abre KaledDental entre pacientes y espera 8 segundos para ver sus citas, la prÃ³xima vez busca una alternativa. Google penaliza pÃ¡ginas lentas en el ranking de bÃºsqueda. Hoy aprendes a medir y mejorar el performance antes de que tus clientes lo sufran.", analogia: "El performance de KaledSoft es como el tiempo de atenciÃ³n en un consultorio dental. Si el paciente espera 30 minutos, busca otro odontÃ³logo. Si el sistema carga en 8 segundos, el usuario abre la competencia. Lighthouse es el cronÃ³metro oficial: mide LCP (cuÃ¡ndo aparece el contenido principal), FID (cuÃ¡ndo puede interactuar), CLS (cuÃ¡nto salta el layout). Google usa estos nÃºmeros para posicionar tu landing page.", concepts: [{ key: "lighthouse", title: "Lighthouse â€” El diagnÃ³stico de performance", body: "F12 â†’ Lighthouse â†’ Generate report. Performance > 90 para KaledSoft. LCP < 2.5s (contenido principal visible). FID < 100ms (responde a interacciÃ³n). CLS < 0.1 (layout no salta). Si el score es < 70, los odontÃ³logos se quejan de que KaledDental estÃ¡ 'lento'." }, { key: "dynamic", title: "dynamic() â€” Lazy loading de componentes pesados", body: "`const GraficoReportes = dynamic(() => import('./GraficoReportes'), { loading: () => <Skeleton /> })`. El grÃ¡fico de reportes de KaledDental (pesado, con Chart.js) solo se descarga cuando el odontÃ³logo navega a la secciÃ³n de reportes â€” no al abrir el dashboard." }], cral: [{ phase: "CONSTRUIR", title: "Mide el performance actual de tu app", desc: "Corre Lighthouse en tu app de KaledWash en Vercel. Documenta el score inicial de Performance, Accessibility, Best Practices, SEO. Identifica los 3 problemas mÃ¡s crÃ­ticos que reporta Lighthouse para tu app." }, { phase: "ROMPER", title: "Importa todos los componentes sin lazy loading", desc: "Importa 5 componentes pesados directamente (sin dynamic()) en tu pÃ¡gina principal de KaledWash. Mide el score de Lighthouse antes y despuÃ©s. Â¿CuÃ¡nto bajÃ³ el score? Â¿CuÃ¡nto aumentÃ³ el JavaScript enviado al browser?" }, { phase: "AUDITAR", title: "Los 3 errores de performance mÃ¡s comunes de IA", desc: "PÃ­dele a Kaled que 'optimice' el performance de tu app. Verifica si sugiere: (1) usar `<img>` en lugar de `<Image>` de Next.js, (2) importar toda una librerÃ­a cuando solo necesitas una funciÃ³n, (3) useEffect sin dependencias que hace fetch en cada render. Â¿Los detectas antes de aplicar las sugerencias?" }, { phase: "LANZAR", title: "Score Lighthouse documentado antes y despuÃ©s", desc: "Captura de Lighthouse antes y despuÃ©s de las optimizaciones. README documenta quÃ© cambios hiciste, por quÃ© y cuÃ¡nto mejorÃ³ cada mÃ©trica." }], quiz: { question: "La pÃ¡gina de reportes de KaledDental importa una librerÃ­a de grÃ¡ficos de 500KB que solo usa 5% de los odontÃ³logos. Â¿CuÃ¡l es el impacto en el performance del dashboard?", options: [{ label: "A", text: "Ninguno â€” la librerÃ­a se descarga en background sin afectar la carga inicial", isCorrect: false, feedback: "Los imports estÃ¡ticos se incluyen en el bundle principal de JavaScript. Si el grÃ¡fico se importa en el layout principal, todos los odontÃ³logos descargan 500KB aunque nunca abran los reportes." }, { label: "B", text: "El 95% de odontÃ³logos descarga 500KB innecesarios â€” aumenta el tiempo de carga inicial del dashboard para todos", isCorrect: true, feedback: "âœ… Â¡Correcto! La soluciÃ³n: `dynamic(() => import('./LibreriaGraficos'), { ssr: false })`. Solo el 5% que usa los reportes descarga los 500KB, cuando los necesita. El 95% restante no paga el costo de esa librerÃ­a. ðŸŽ¯" }, { label: "C", text: "Solo afecta a odontÃ³logos con conexiÃ³n lenta â€” los que tienen fibra no lo notan", isCorrect: false, feedback: "El peso del JavaScript afecta el tiempo de parse/execute, no solo el de descarga. En dispositivos mÃ³viles y computadores de gama media (comunes en Colombia), 500KB de JS adicional puede agregar 1-3 segundos de tiempo de carga incluso con buena conexiÃ³n." }, { label: "D", text: "Tailwind optimiza automÃ¡ticamente los imports de librerÃ­as externas", isCorrect: false, feedback: "Tailwind optimiza las clases CSS no usadas, no los imports de JavaScript. Las librerÃ­as externas deben optimizarse manualmente con dynamic() o import dinÃ¡mico." }] } },
    { orden: 12, semana: 8, dia: "VIERNES", titulo: "Dark mode, accesibilidad y cierre del MÃ³dulo 2", descripcion: "Dark mode con next-themes, variables CSS, accesibilidad fundamental. El frontend completo de tu SaaS integrado y desplegado.", duracion: 180, sessionType: "ENTREGABLE", video: { url: "https://www.youtube.com/watch?v=uknRNaFwq20", title: "Dark Mode en Next.js con next-themes" }, kaledIntro: "KaledSoft lanzÃ³ dark mode en todos sus productos porque **el 78% de los usuarios prefieren dark mode para uso prolongado**. Los odontÃ³logos pasan 8+ horas al dÃ­a frente a la pantalla â€” dark mode reduce la fatiga visual. La accesibilidad no es opcional: en Colombia, el decreto 1078 de 2015 obliga a que los portales del Estado sean accesibles. Si algÃºn cliente de KaledSoft es entidad pÃºblica, el sistema debe cumplir.", analogia: "Dark mode es como tener dos uniformes en KaledWash: el blanco para el dÃ­a (modo claro) y el azul oscuro para el turno de noche (modo oscuro). next-themes es el sistema que recuerda quÃ© uniforme prefiere cada empleado y lo aplica automÃ¡ticamente cuando llega. Accesibilidad es construir las instalaciones del lavadero de forma que tambiÃ©n puedan trabajar personas con discapacidad â€” no es optional, es inclusiÃ³n.", concepts: [{ key: "next-themes", title: "next-themes â€” Dark mode en 5 minutos", body: "Instala `next-themes`. Envuelve el layout con `<ThemeProvider>`. Usa `useTheme()` para el toggle. Configura las clases CSS con `dark:bg-slate-900 dark:text-white`. El sistema recuerda la preferencia del usuario en localStorage." }, { key: "a11y", title: "Accesibilidad mÃ­nima para KaledSoft", body: "Contraste mÃ­nimo 4.5:1 para texto normal (verificar con Chrome DevTools â†’ Accessibility). `aria-label` en botones sin texto. `alt` en imÃ¡genes. Tab order lÃ³gico. `role='alert'` para notificaciones importantes (ej: 'VehÃ­culo registrado exitosamente')." }], cral: [{ phase: "CONSTRUIR", title: "Dark mode en el dashboard de KaledWash", desc: "Implementa dark mode con next-themes. El toggle estÃ¡ en el header. El dark mode usa los colores del design system de KaledSoft (#161A22 background, #1D212B surface). La preferencia persiste entre sesiones." }, { phase: "ROMPER", title: "Navega el dashboard solo con teclado", desc: "Desconecta el mouse. Navega el dashboard de KaledWash usando solo Tab, Enter y flechas. Â¿Puedes: registrar una nueva orden? Â¿cambiar el estado de una orden? Â¿buscar un cliente? Documenta quÃ© flujos son imposibles sin mouse y por quÃ©." }, { phase: "AUDITAR", title: "Score de Accessibility en Lighthouse", desc: "Corre Lighthouse en tu app. Â¿El score de Accessibility es > 90? Â¿QuÃ© problemas especÃ­ficos identifica? Â¿Las imÃ¡genes tienen alt? Â¿Los botones tienen label accesible? Â¿El contraste de color pasa el umbral mÃ­nimo?" }, { phase: "LANZAR", title: "Frontend completo del SaaS â€” Entregable integrador MÃ³dulo 2", desc: "Frontend completo de tu SaaS en Vercel con dark mode, responsive, Lighthouse Performance + Accessibility > 90. README con arquitectura de componentes, decisiones de estado y reflexiÃ³n de 200 palabras sobre quÃ© generÃ³ la IA vs quÃ© construiste tÃº." }], quiz: { question: "El botÃ³n 'Registrar nueva orden' en KaledWash solo tiene un Ã­cono '+' sin texto visible. Un usuario con discapacidad visual usa lectores de pantalla. Â¿QuÃ© escucha cuando llega al botÃ³n?", options: [{ label: "A", text: "'BotÃ³n' â€” el lector de pantalla identifica el tipo de elemento", isCorrect: false, feedback: "El lector de pantalla dice 'botÃ³n' pero no quÃ© hace el botÃ³n. El usuario no sabe si es el botÃ³n de guardar, de cancelar o de registrar una nueva orden." }, { label: "B", text: "Nada Ãºtil â€” sin aria-label o texto visible, el lector de pantalla solo anuncia 'botÃ³n' sin contexto", isCorrect: true, feedback: "âœ… Â¡Correcto! La soluciÃ³n: `<button aria-label='Registrar nueva orden de lavado'>+</button>`. El lector de pantalla anunciarÃ­a: 'Registrar nueva orden de lavado, botÃ³n'. Contexto completo, acciÃ³n clara. Los usuarios con VoiceOver, NVDA o JAWS son clientes reales de los clientes de KaledSoft. ðŸŽ¯" }, { label: "C", text: "El emoji del Ã­cono '+' â€” los lectores de pantalla leen emojis", isCorrect: false, feedback: "Los lectores de pantalla sÃ­ leen emojis (como 'signo mÃ¡s' o 'mas'), pero eso no describe la acciÃ³n del botÃ³n. El usuario escucharÃ­a 'signo mÃ¡s botÃ³n' â€” sin contexto sobre quÃ© hace ese botÃ³n." }, { label: "D", text: "Solo es problema en Safari con VoiceOver â€” Chrome y Firefox lo manejan diferente", isCorrect: false, feedback: "La falta de aria-label afecta a todos los lectores de pantalla en todos los navegadores. NVDA (Windows), JAWS (Windows), VoiceOver (Mac/iOS), TalkBack (Android) â€” todos necesitan el aria-label para dar contexto." }], entregable: { title: "Frontend SaaS completo â€” Entregable integrador MÃ³dulo 2", desc: "Frontend completo de tu SaaS con dark mode, responsive, accesible. Lighthouse Performance + Accessibility > 90. README con arquitectura y reflexiÃ³n sobre IA.", isFinal: true, items: ["Dark mode con next-themes funcionando y persistente", "Responsive verificado en mÃ³vil, tablet y desktop", "Lighthouse Performance > 90 documentado con screenshot", "Lighthouse Accessibility > 90 documentado con screenshot", "Formularios con RHF + Zod validaciÃ³n completa", "Estado global con Zustand en al menos 1 store", "Los 4 estados de UI en todas las vistas con datos", "README: arquitectura, decisiones, reflexiÃ³n IA vs trabajo propio (200+ palabras)"] } } },
  ];

